import { Component, OnInit } from '@angular/core';

@Component({
  selector: 'app-home',
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.css']
})
export class HomeComponent implements OnInit {

  dias: number = 0;

  ngOnInit() {
    this.calcularDias();
    setInterval(() => this.calcularDias(), 1000 * 60 * 60);
  }

  calcularDias() {
    const hoje = new Date();
    const casamento = new Date('2026-09-19');

    const diff = casamento.getTime() - hoje.getTime();
    this.dias = Math.ceil(diff / (1000 * 60 * 60 * 24));
  }
}
